	endTime := time.Now()
	session.LastActivity = endTime
	// 计算面试时长
	duration := int64(endTime.Sub(session.StartTime).Seconds())
	endTimeMs := endTime.UnixMilli()
	totalQuestions := session.QuestionCount
	answeredQuestions := session.QuestionCount // 已回答的问题数 = 主问题数

	// 取消面试循环，立即关闭 SSE 连接
